css:
.loader {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
   width: 35px;
   aspect-ratio: 1;
   --c:no-repeat linear-gradient(var(--loader-color, #0891b2) 0 0);
   background: var(--c) 0 0, var(--c) 100% 0, var(--c) 100% 100%, var(--c) 0 100%;
   animation: l1 1s infinite alternate;
}
@keyframes l1  {
  0% {background-size: 0 4px,4px 0 ,0 4px,4px 0 }
25% {background-size: 100% 4px,4px 0 ,0 4px,4px 0 }
50% {background-size: 100% 4px,4px 100%,0 4px,4px 0 }
75% {background-size: 100% 4px,4px 100%,100% 4px,4px 0 }
90%, 100% {background-size: 100% 4px,4px 100%,100% 4px,4px 100%}
}
